SELECT SUM(daily_revenue) AS total_daily_revenue
FROM box_office
WHERE film_id = 1;

SELECT average_rating
FROM film_statistics
WHERE film_id = 1;

SELECT film_id, total_reviews
FROM film_statistics
ORDER BY total_reviews DESC;

SELECT film_id
FROM film_statistics
WHERE average_rating = (SELECT MAX(average_rating) FROM film_statistics);
